{ title: "Ek Chhota Sa Khat рҹ’Ң", text: "Meri Anu,\n\nKabhi kabhi lagta hai main tumhe poora express nahi kar paata.\nToh aaj likhta hoon.\n\nTum meri zindagi mein ayi aur sab badal diya.\nMera sochna. Mera rehna. Mera jeena.\nSab better ho gaya.\n\nThank you. For being you. For choosing me.\n\nForever yours,\nVishu вқӨпёҸ" },
{ title: "Jab Main Nahi Bolta рҹ’ң", text: "Anu,\n\nKuch cheezein main bol nahi paata.\nPar feel karta hoon.\n\nJaise вҖ” jab tum sad hoti ho, mera dil heavy ho jaata hai.\nJab tum khush hoti ho, main bina reason ke muskurane lagta hoon.\nJab tum kuch achieve karti ho, main proud feel karta hoon jaise mere khud ka kuch ban gaya.\n\nYe connection hai hamara. Real wala.\nWords se zyada. рҹ’ң" },
{ title: "Raat Ke 2 Baje Ka Khat рҹҢҷ", text: "Anu,\n\n2 baj gaye hain.\nNeend nahi aa rahi.\nAur tumhare baare mein soch raha hoon.\n\nKitna kuch kehna hai.\nPar neend mein soye hoge tum.\nToh ye likhta hoon.\n\nBas itna вҖ” tum meri sabse pyaari cheez ho is duniya mein.\nAur ye hamesha rahega.\n\nGood night, love. рҹҢҷвқӨпёҸ" },
{ title: "Aaj Ka Khat рҹ’•", text: "Mere Anu,\n\nAaj tumhare baare mein kitna socha.\nKitna miss kiya.\nKitna chahaa ki tum paas hoti.\n\nPar phir sochi вҖ” ye feeling hi toh pyaar hai na?\nYe khinchaav. Ye yaad.\nYe hi real hai.\n\nAur ye real hai kyunki tum real ho.\nMeri real duniya.\n\nвҖ” Tumhara Vishu рҹ’ң" },
{ title: "Woh Din Jab вқӨпёҸ", text: "Woh din yaad hai mujhe, Anu...\nJab pehli baar tumse baat ki.\nMain itna nervous tha.\nAur tum itni naturally cool the.\n\nTab se aaj tak вҖ” tum hi ho.\nSabse pehle yaad aane wali.\nSabse akhri sone se pehle sochne wali.\n\nHamesha. Sirf tum. рҹ’ң" },
{ title: "Ek Baat Sunni Hai рҹ’Ң", text: "Anu,\n\nEk baat kehni hai jo main aksar nahi keh paata:\nMain tumse proud hoon.\n\nHar cheez mein.\nJab tum handle karti ho sab kuch akele.\nJab tum smile karti ho mushkil mein.\nJab tum continue karti ho jab duniya rokti hai.\n\nTum bahut brave ho.\nAur main hamesha tumhara supporter hoon.\nForever. рҹ’ң" }


